flow.set('lastPrices', {});
msg.payload = '🗑 Stored fuel prices have been reset.\nNext auto-check will establish a new baseline.';
return msg;

// ════════════════════════════════════════════════
// ⚙️  CONFIGURATION — Edit these values!
// ════════════════════════════════════════════════

// 1) Your Tankerkoenig API key
//    Get one free at: https://creativecommons.tankerkoenig.de
const API_KEY = "YOUR_API_KEY_HERE";

// 2) Gas stations: Name → Tankerkoenig UUID
//    Find station UUIDs at: https://creativecommons.tankerkoenig.de/TanksijsonApiDetaile
const STATIONS = {
    "HEM":  "e1a15081-256b-9107-e040-0b0a3dfe563c",
    "JET":  "51d4b716-a095-1aa0-e100-80009459e03a"
};

// 3) Price change thresholds for auto-alerts (in EUR)
//    Example: 0.02 = alert when price changes by ≥ 2 cents
//    Set to 0 to alert on ANY change
const THRESHOLDS = {
    e5:     0.02,
    e10:    0.02,
    diesel: 0.02
};

// ════════════════════════════════════════════════
// ⚠️  Don't edit below this line
// ════════════════════════════════════════════════

msg.stations = STATIONS;
msg.thresholds = THRESHOLDS;

const ids = Object.values(STATIONS).join(',');
msg.url = `https://creativecommons.tankerkoenig.de/json/prices.php?ids=${ids}&apikey=${API_KEY}`;

return msg;

const data = msg.payload;
const stations = msg.stations;
const thresholds = msg.thresholds;
const mode = msg.mode || 'manual';
const fuelFilter = msg.fuelFilter || 'all';

// Check API response
if (!data || !data.ok) {
    msg.payload = '⚠️ Error fetching fuel prices: ' + 
        (data && data.message ? data.message : 'No response from API');
    return msg;
}

const prices = data.prices;
const fuelTypes = ['e5', 'e10', 'diesel'];
const fuelLabels = { e5: 'Super E5', e10: 'Super E10', diesel: 'Diesel' };
const fuelEmoji = { e5: '🟢', e10: '🔵', diesel: '🟡' };

// Get stored prices from flow context
const stored = flow.get('lastPrices') || {};

let alerts = [];
let lines = [];

// Timestamp
const now = new Date().toLocaleString('de-DE', {
    timeZone: 'Europe/Berlin',
    hour: '2-digit', minute: '2-digit',
    day: '2-digit', month: '2-digit', year: 'numeric'
});

for (const [name, uuid] of Object.entries(stations)) {
    const sp = prices[uuid];

    if (!sp || sp.status !== 'open') {
        lines.push(`❌ ${name}: Closed`);
        continue;
    }

    const stKey = name;
    if (!stored[stKey]) stored[stKey] = {};

    let stationLines = [];

    for (const fuel of fuelTypes) {
        if (fuelFilter !== 'all' && fuel !== fuelFilter) continue;

        const price = sp[fuel];
        if (price === null || price === undefined || price === false) continue;

        const oldPrice = stored[stKey][fuel];
        const hasOld = (oldPrice !== undefined && oldPrice !== null);
        const delta = hasOld ? (price - oldPrice) : 0;

        let arrow = '';
        let deltaStr = '';
        if (hasOld && delta !== 0) {
            arrow = delta > 0 ? ' ▲' : ' ▼';
            const sign = delta > 0 ? '+' : '';
            deltaStr = ` (${sign}${(delta * 100).toFixed(1)}¢)`;
        }

        stationLines.push(
            `  ${fuelEmoji[fuel]} ${fuelLabels[fuel]}: ${price.toFixed(3)} €${deltaStr}${arrow}`
        );

        // Check threshold for auto-alerts
        if (mode === 'auto' && hasOld) {
            const threshold = thresholds[fuel] || 0.02;
            if (Math.abs(delta) >= threshold) {
                const sign = delta > 0 ? '+' : '';
                const icon = delta > 0 ? '▲' : '▼';
                alerts.push(
                    `${icon} ${name} ${fuelLabels[fuel]}: ` +
                    `${oldPrice.toFixed(3)} → ${price.toFixed(3)} € ` +
                    `(${sign}${(delta * 100).toFixed(1)}¢)`
                );
            }
        }

        // Store new price
        stored[stKey][fuel] = price;
    }

    if (stationLines.length > 0) {
        lines.push(`⛽ ${name}:`);
        lines = lines.concat(stationLines);
    }
}

// Save prices to flow context
flow.set('lastPrices', stored);

if (mode === 'auto') {
    // Only send if there are threshold alerts
    if (alerts.length === 0) return null;
    msg.payload = `🔔 Fuel Price Alert\n${now}\n\n${alerts.join('\n')}`;
} else {
    // Manual query: always send
    const filterNote = fuelFilter !== 'all' 
        ? ` (${fuelLabels[fuelFilter]})` 
        : '';
    msg.payload = `⛽ Fuel Prices${filterNote}\n${now}\n\n${lines.join('\n')}`;
}

return msg;
